javascript:(function(){'use strict';const C={DELAY_MIN:35e3,DELAY_MAX:85e3,MAX_UF:22,SC_MIN:500,SC_MAX:2e3,SC_STEP:700,MAX_STUCK:6,TIMEOUT:18e5};const S={nm:[],sel:new Set,phase:'idle',cnt:0,stop:false,t0:null};const sl=ms=>new Promise(r=>setTimeout(r,ms));const rnd=(a,b)=>Math.floor(Math.random()*(b-a+1))+a;const esc=s=>String(s??'').replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;').replace(/"/g,'&quot;').replace(/'/g,'&#39;');const uname=h=>{if(!h)return null;return(h.split('/')[1]??'').split('?')[0].toLowerCase()||null};const icolor=c=>{const p=['#1e3a5f','#1e4d3a','#3d2260','#5c2020','#1a4a4a','#3a3a1e','#2d1f4f','#1f3d2d'];return p[((c||'a').toLowerCase().charCodeAt(0)-97+26)%p.length%8]};const expired=()=>S.t0&&(Date.now()-S.t0)>C.TIMEOUT;const SYS=new Set(['search','explore','notifications','messages','settings','home','i','following','followers']);function fb(cell){const t=cell.innerText||cell.textContent||'';return/te sigue\b/i.test(t)||/follows you\b/i.test(t)}function xi(cell){let u=null;for(const a of cell.querySelectorAll('a[href^="/"]')){const p=uname(a.getAttribute('href'));if(p&&!p.includes('#')&&!SYS.has(p)){u=p;break}}const n=cell.querySelector('[data-testid="User-Name"] span span')||cell.querySelector('[data-testid="UserName"] span span');return{username:u,displayName:n?.textContent?.trim()||u||'?'}}async function scan(cb){window.scrollTo(0,0);await sl(1200);const seen=new Set;let sk=0,lh=0;while(sk<C.MAX_STUCK&&!S.stop){if(expired())break;document.querySelectorAll('[data-testid="UserCell"]').forEach(c=>{const{username:u,displayName:d}=xi(c);if(!u||seen.has(u))return;seen.add(u);if(!fb(c))S.nm.push({username:u,displayName:d})});cb(seen.size,S.nm.length);window.scrollBy(0,C.SC_STEP);await sl(rnd(C.SC_MIN,C.SC_MAX));const nh=document.body.scrollHeight;sk=nh===lh?sk+1:0;lh=nh}return{scanned:seen.size,found:S.nm.length}}function findBtn(c){return c.querySelector('[data-testid$="-follow"]')||c.querySelector('button[aria-label*="Unfollow" i]')||c.querySelector('button[aria-label*="Dejar de seguir" i]')||[...c.querySelectorAll('button')].find(b=>/siguiendo|following/i.test(b.textContent))||null}async function waitCfm(t=4e3){const d=Date.now()+t;return new Promise(r=>{const ck=()=>{const b=document.querySelector('[data-testid="confirmationSheetConfirm"]');if(b){b.click();return r(true)}Date.now()<d?setTimeout(ck,150):r(true)};ck()})}async function processQ(q,onP,onC){S.cnt=0;window.scrollTo(0,0);await sl(1500);const pnd=new Set(q.map(u=>u.username));let done=0,lh=0,sk=0;while(pnd.size>0&&!S.stop&&sk<7){if(expired())break;const cells=document.querySelectorAll('[data-testid="UserCell"]');let fnd=false;for(const c of cells){const{username:u}=xi(c);if(!u||!pnd.has(u))continue;fnd=true;pnd.delete(u);c.scrollIntoView({behavior:'smooth',block:'center'});await sl(500+Math.random()*400);const btn=findBtn(c);if(!btn)continue;onP(done+1,q.length,u);try{btn.dispatchEvent(new MouseEvent('mouseover',{bubbles:true}));await sl(250+Math.random()*150);btn.click();await sl(800+Math.random()*300);await waitCfm();await sl(400);S.cnt++;done++}catch(e){console.error('[XUF]',e)}if(S.cnt>=C.MAX_UF)return{done,limit:true,stop:false};if(pnd.size>0&&!S.stop){const s=Math.round(rnd(C.DELAY_MIN,C.DELAY_MAX)/1e3);await onC(s,done,q.length)}}if(!fnd){window.scrollBy(0,C.SC_STEP);await sl(rnd(C.SC_MIN,C.SC_MAX));const nh=document.body.scrollHeight;sk=nh===lh?sk+1:0;lh=nh}else sk=0}return{done,limit:false,stop:S.stop}}const CSS=`#xo{position:fixed;inset:0;z-index:9999999;background:#0f0f0f;color:#e0e0e0;font-family:-apple-system,BlinkMacSystemFont,'Segoe UI',Roboto,sans-serif;font-size:14px;line-height:1.55;display:flex;flex-direction:column;align-items:center;justify-content:center;overflow:hidden}@keyframes xi{from{opacity:0;transform:translateY(10px)}to{opacity:1;transform:translateY(0)}}.xa{animation:xi .22s ease}.xc{display:flex;flex-direction:column;align-items:center;gap:28px;width:100%;max-width:440px;padding:56px 32px;text-align:center}.xbr{font-size:10px;font-weight:700;letter-spacing:2.5px;text-transform:uppercase;color:#2e2e2e;margin:0}@keyframes xs{to{transform:rotate(360deg)}}.xsp{width:30px;height:30px;border:2px solid #1c1c1c;border-top-color:#666;border-radius:50%;animation:xs .85s linear infinite;flex-shrink:0}.xh{font-size:20px;font-weight:600;color:#e0e0e0;margin:0;letter-spacing:-.3px}.xsb{font-size:13px;color:#484848;margin:0;max-width:320px;line-height:1.6}.xbn{font-size:80px;font-weight:700;color:#e0e0e0;line-height:1;margin:0;letter-spacing:-4px}.xt{font-size:17px;font-weight:600;color:#606060;margin:0;min-height:24px}.xst{display:flex;gap:52px;align-items:flex-end}.xsi{display:flex;flex-direction:column;align-items:center;gap:5px}.xsn{font-size:42px;font-weight:700;color:#e0e0e0;line-height:1;letter-spacing:-1.5px;min-width:60px;text-align:center}.xsl{font-size:10px;color:#303030;text-transform:uppercase;letter-spacing:1.2px}.xpw{width:100%;max-width:360px;display:flex;flex-direction:column;align-items:center;gap:10px}.xpt{width:100%;height:2px;background:#1c1c1c;border-radius:1px;overflow:hidden}.xpf{height:100%;background:#e0e0e0;border-radius:1px;transition:width .35s ease}.xpl{font-size:11px;color:#383838}#xo.xpm{align-items:stretch;justify-content:flex-start}.xpn{display:flex;flex-direction:column;width:100%;height:100%;max-width:860px;margin:0 auto}.xph{display:flex;align-items:center;justify-content:space-between;padding:18px 28px;border-bottom:1px solid #181818;flex-shrink:0;gap:16px}.xphr{display:flex;align-items:center;gap:20px}.xcl{font-size:12px;color:#404040;white-space:nowrap}.xcl strong{color:#c0c0c0;font-weight:600}.xwb{background:#161200;border-bottom:1px solid #201800;padding:8px 28px;font-size:12px;color:#585030;flex-shrink:0}.xwb strong{color:#907830}.xtb{display:flex;align-items:center;gap:8px;padding:11px 28px;border-bottom:1px solid #181818;flex-shrink:0}.xts{flex:1;overflow-y:auto;scrollbar-width:thin;scrollbar-color:#1c1c1c transparent}.xtb1::-webkit-scrollbar{width:3px}.xtb1::-webkit-scrollbar-thumb{background:#1c1c1c}.xta{width:100%;border-collapse:collapse}.xtr{border-bottom:1px solid #131313;transition:background .1s}.xtr:hover{background:#111}.xtd{padding:10px 12px;vertical-align:middle}.xtdc{width:48px;text-align:center}.xtda{width:52px}.xav{width:34px;height:34px;border-radius:50%;display:flex;align-items:center;justify-content:center;font-size:13px;font-weight:700;color:rgba(255,255,255,.65);flex-shrink:0}.xun{display:block;font-weight:600;font-size:14px;color:#d0d0d0}.xuh{display:block;font-size:12px;color:#404040;margin-top:2px}.xpft{display:flex;align-items:center;justify-content:space-between;padding:16px 28px;border-top:1px solid #181818;flex-shrink:0;gap:16px}.xln{font-size:12px;color:#303030;margin:0}.xb{padding:8px 20px;border-radius:5px;border:none;cursor:pointer;font-size:13px;font-weight:600;transition:background .15s,color .15s,opacity .15s;white-space:nowrap;font-family:inherit;line-height:1.4}.xb:disabled{opacity:.3;cursor:not-allowed;pointer-events:none}.xbp{background:#e0e0e0;color:#0f0f0f}.xbp:hover:not(:disabled){background:#fff}.xbg{background:transparent;color:#505050;border:1px solid #1e1e1e}.xbg:hover:not(:disabled){background:#181818;color:#c0c0c0;border-color:#282828}.xbi{background:none;border:none;cursor:pointer;font-size:11px;font-weight:700;color:#303030;padding:6px 8px;border-radius:4px;transition:color .1s,background .1s;font-family:inherit;line-height:1}.xbi:hover{color:#e0e0e0;background:#181818}.xcb{width:14px;height:14px;cursor:pointer;accent-color:#c0c0c0}.xcb:disabled{opacity:.3;cursor:not-allowed}`;let ov=null;function inj(){if(!document.getElementById('xuf-css2')){const s=document.createElement('style');s.id='xuf-css2';s.textContent=CSS;document.head.appendChild(s)}}function mnt(){document.getElementById('xo')?.remove();inj();ov=document.createElement('div');ov.id='xo';document.body.appendChild(ov);return ov}function umnt(){ov?.remove();ov=null}function showScan(){if(!ov)return;ov.classList.remove('xpm');ov.innerHTML=`<div class="xc xa"><p class="xbr">Unfollowers-X &nbsp; v1.2</p><div class="xsp"></div><p class="xh">Escaneando lista de seguidos</p><p class="xsb" id="xss">Iniciando...</p><div class="xst"><div class="xsi"><span class="xsn" id="xsc">0</span><span class="xsl">Revisados</span></div><div class="xsi"><span class="xsn" id="xsf">0</span><span class="xsl">No-mutuos</span></div></div><button class="xb xbg" id="xcan">Cancelar</button></div>`;document.getElementById('xcan').onclick=()=>{S.stop=true}}function upScan(sc,fo){const s=document.getElementById('xss'),a=document.getElementById('xsc'),b=document.getElementById('xsf');if(s)s.textContent='Escaneando usuario '+sc+'...';if(a)a.textContent=sc;if(b)b.textContent=fo}function showRes(nm){if(!ov)return;ov.classList.add('xpm');const sw=nm.length>C.MAX_UF;const rows=nm.map(({username:u,displayName:d})=>{const i=(d[0]||u[0]||'U').toUpperCase();return`<tr class="xtr"><td class="xtd xtdc"><input type="checkbox" class="xcb" data-u="${esc(u)}" checked/></td><td class="xtd xtda"><div class="xav" style="background:${icolor(i)}">${esc(i)}</div></td><td class="xtd"><span class="xun">${esc(d)}</span><span class="xuh">@${esc(u)}</span></td></tr>`}).join('');ov.innerHTML=`<div class="xpn xa"><div class="xph"><p class="xbr">Unfollowers-X &nbsp; v1.2</p><div class="xphr"><span class="xcl"><strong id="xsc2">${nm.length}</strong> de ${nm.length} seleccionados</span><button class="xbi" id="xcls">X</button></div></div>${sw?`<div class="xwb"><strong>Atencion:</strong> ${nm.length} detectados. Limite: <strong>${C.MAX_UF} por sesion</strong>.</div>`:''}<div class="xtb"><button class="xb xbg" id="xsa">Seleccionar todo</button><button class="xb xbg" id="xda">Deseleccionar todo</button></div><div class="xts"><table class="xta"><tbody>${rows}</tbody></table></div><div class="xpft"><p class="xln">Maximo ${C.MAX_UF} unfollows por sesion</p><button class="xb xbp" id="xuf">Dejar de seguir seleccionados</button></div></div>`;S.sel.clear();nm.forEach(u=>S.sel.add(u.username));const upC=()=>{const e=document.getElementById('xsc2');if(e)e.textContent=S.sel.size;const b=document.getElementById('xuf');if(b)b.disabled=S.sel.size===0};ov.querySelectorAll('.xcb').forEach(cb=>{cb.addEventListener('change',()=>{cb.checked?S.sel.add(cb.dataset.u):S.sel.delete(cb.dataset.u);upC()})});document.getElementById('xsa').onclick=()=>{ov.querySelectorAll('.xcb').forEach(cb=>{cb.checked=true;S.sel.add(cb.dataset.u)});upC()};document.getElementById('xda').onclick=()=>{ov.querySelectorAll('.xcb').forEach(cb=>{cb.checked=false;S.sel.delete(cb.dataset.u)});upC()};document.getElementById('xcls').onclick=()=>umnt();document.getElementById('xuf').onclick=()=>{if(S.sel.size>0)doUF()}}function showUF(t){if(!ov)return;ov.classList.remove('xpm');ov.innerHTML=`<div class="xc xa"><p class="xbr">Unfollowers-X &nbsp; v1.2</p><p class="xh" id="xufh">Preparando...</p><p class="xt" id="xuft"></p><div class="xpw"><div class="xpt"><div class="xpf" id="xpf" style="width:0%"></div></div><span class="xpl" id="xpl">0 / ${t}</span></div><p class="xsb" id="xcd"></p><button class="xb xbg" id="xst2">Detener</button></div>`;document.getElementById('xst2').onclick=()=>{S.stop=true;const b=document.getElementById('xst2');if(b){b.textContent='Deteniendo...';b.disabled=true}}}function upUF(c,t,u){const pct=Math.round(c/t*100);const f=document.getElementById('xpf'),l=document.getElementById('xpl'),h=document.getElementById('xufh'),tg=document.getElementById('xuft');if(f)f.style.width=pct+'%';if(l)l.textContent=c+' / '+t;if(h)h.textContent='Dejando de seguir...';if(tg)tg.textContent='@'+u}async function runCD(s,c,t){const e=document.getElementById('xcd');for(let r=s;r>0;r--){if(S.stop)break;if(e)e.textContent='Esperando '+r+'s antes del siguiente...';await sl(1e3)}if(e)e.textContent=''}function showDone(n,lim,stp){if(!ov)return;ov.classList.remove('xpm');const sub=stp?'Proceso detenido manualmente.':lim?`Limite de sesion (${C.MAX_UF}). Espera 2-3 horas antes de continuar.`:n===0?'No se encontraron cuentas no-mutuas.':`${n} ${n===1?'usuario eliminado':'usuarios eliminados'} correctamente.`;ov.innerHTML=`<div class="xc xa"><p class="xbr">Unfollowers-X &nbsp; v1.2</p>${n>0?`<p class="xbn">${n}</p>`:''}<p class="xh">${lim?'Limite alcanzado':stp?'Proceso detenido':'Completado'}</p><p class="xsb">${esc(sub)}</p><button class="xb xbp" id="xfc">Cerrar</button></div>`;document.getElementById('xfc').onclick=()=>umnt()}async function runScanMain(){S.t0=Date.now();S.stop=false;S.nm=[];S.sel.clear();showScan();await scan((sc,fo)=>upScan(sc,fo));if(S.stop){umnt();return}if(S.nm.length===0){showDone(0,false,false);return}showRes(S.nm)}async function doUF(){const q=S.nm.filter(u=>S.sel.has(u.username)).slice(0,C.MAX_UF);if(!q.length)return;S.stop=false;showUF(q.length);const{done,limit,stop}=await processQ(q,(c,t,u)=>upUF(c,t,u),(s,c,t)=>runCD(s,c,t));showDone(done,limit,stop)}if(!window.location.href.includes('/following')){if(!confirm('Unfollowers-X v1.2\n\nNavega a tu pagina /following antes de ejecutar.\n\nContinuar de todas formas?'))return}mnt();runScanMain();console.log('%cUnfollowers-X v1.2','color:#606060;font-weight:bold')})();
